import { Context, Effect, Layer } from "effect";

import {
  NotificationChannelRegistry,
  type NotificationChannelShape,
} from "./channel";
import { NotificationMessage, NotificationSendError } from "./schema";

export interface NotificationServiceShape {
  readonly send: (
    message: NotificationMessage,
  ) => Effect.Effect<void, NotificationSendError>;
}

export class NotificationService extends Context.Service<
  NotificationService,
  NotificationServiceShape
>()("NotificationService", {
  make: Effect.gen(function* () {
    const registry = yield* NotificationChannelRegistry;

    const send = Effect.fn("NotificationService.send")(
      (message: NotificationMessage) =>
        Effect.gen(function* () {
          for (const [key, payload] of Object.entries(message)) {
            const channel = registry.channels.find((item) => item.key === key);

            if (!channel) {
              return yield* new NotificationSendError({
                channel: key,
                message: `No notification channel installed for ${key}`,
              });
            }

            yield* channel.send(payload, message);
          }
        }),
    );

    return { send };
  }),
}) {
  static readonly layer = Layer.effect(this, this.make);

  static readonly makeLayer = (
    channels: ReadonlyArray<NotificationChannelShape>,
  ) =>
    this.layer.pipe(Layer.provide(NotificationChannelRegistry.layer(channels)));

  static readonly noopLayer = this.layer.pipe(
    Layer.provide(NotificationChannelRegistry.emptyLayer),
  );
}

import { Context, Effect, Layer } from "effect";

import { NotificationMessage, NotificationSendError } from "./schema";

export interface NotificationChannelShape {
  readonly key: string;
  readonly send: (
    payload: unknown,
    message: NotificationMessage,
  ) => Effect.Effect<void, NotificationSendError>;
}

export interface NotificationChannelRegistryShape {
  readonly channels: ReadonlyArray<NotificationChannelShape>;
}

export class NotificationChannelRegistry extends Context.Service<
  NotificationChannelRegistry,
  NotificationChannelRegistryShape
>()("NotificationChannelRegistry") {
  static readonly layer = (channels: ReadonlyArray<NotificationChannelShape>) =>
    Layer.succeed(this, { channels });

  static readonly emptyLayer = Layer.succeed(this, {
    channels: [],
  });
}

import { Schema } from "effect";

export const NotificationMessage = Schema.Record(
  Schema.String,
  Schema.Unknown,
).annotate({
  identifier: "NotificationMessage",
  title: "Notification message",
  description:
    "A dynamic notification envelope keyed by channel capability. Installed channels send the payload matching their key.",
  examples: [
    {
      email: {
        to: "user@example.com",
        subject: "Welcome",
        text: "Thanks for signing up.",
      },
      discord: {
        content: "A user signed up.",
      },
    },
  ],
});

export class NotificationSendError extends Schema.TaggedErrorClass<NotificationSendError>()(
  "NotificationSendError",
  {
    message: Schema.String,
    channel: Schema.optional(Schema.String),
    error: Schema.optional(Schema.Defect),
  },
) {}

export type NotificationMessage = typeof NotificationMessage.Type;

